def longest_increasing_subsequence(arr):
    """Find the length of the longest increasing subsequence using patience sorting."""
    tails = []
    for num in arr:
        # Find the first index in tails that is >= num
        left, right = 0, len(tails)
        while left < right:
            mid = (left + right) // 2
            if tails[mid] >= num:
                right = mid
            else:
                left = mid + 1
        if left == len(tails):
            tails.append(num)
        else:
            tails[left] = num
    return len(tails)

